import axios from 'axios';
import { QueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';

export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5,
      gcTime: 1000 * 60 * 10,
      retry: (failureCount, error: unknown) => {
        if (axios.isAxiosError(error)) {
          const status = error.response?.status;
          if (status === 401 || status === 403 || status === 404) return false;
        }
        return failureCount < 2;
      },
      refetchOnWindowFocus: false,
    },
    mutations: {
      onError: (error: unknown) => {
        const message = axios.isAxiosError(error)
          ? (error.response?.data?.message ?? 'Что-то пошло не так')
          : 'Что-то пошло не так';
        toast.error(message);
      },
    },
  },
});

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatDate(
  date: string | Date | null | undefined,
  options: Intl.DateTimeFormatOptions = { day: '2-digit', month: 'short', year: 'numeric' }
): string {
  if (!date) return '—';
  const d = new Date(date);
  if (isNaN(d.getTime())) return '—';
  return new Intl.DateTimeFormat('ru-RU', options).format(d);
}

export function formatCurrency(
  amount: number,
  currency = 'USD',
  locale = 'en-US'
): string {
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency,
    minimumFractionDigits: 0,
  }).format(amount);
}

export function formatNumber(value: number, locale = 'en-US'): string {
  return new Intl.NumberFormat(locale).format(value);
}

export function debounce<TArgs extends unknown[]>(
  fn: (...args: TArgs) => void,
  delay: number
): (...args: TArgs) => void {
  let timeout: ReturnType<typeof setTimeout>;
  return (...args: TArgs) => {
    clearTimeout(timeout);
    timeout = setTimeout(() => fn(...args), delay);
  };
}

export function getInitials(name: string | null | undefined): string {
  if (!name) return '?';
  return name.split(' ').slice(0, 2).map((n) => n[0] ?? '').join('').toUpperCase();
}

export function truncate(str: string | null | undefined, maxLength: number): string {
  if (!str) return '';
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength - 3) + '...';
}

export function generateId(): string {
  return Math.random().toString(36).slice(2, 11);
}

export function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export function extractList<T>(data: unknown): T[] {
  const r = (data as any)?.data?.data?.response;
  if (Array.isArray(r)) return r;
  if (r && typeof r === 'object') return [r as T];
  return [];
}

export function extractCount(data: unknown): number {
  return (data as any)?.data?.data?.count ?? 0;
}

export function extractSingle<T>(data: unknown): T | null {
  const r = (data as any)?.data?.data?.response;
  if (Array.isArray(r)) return r[0] ?? null;
  return (r as T) ?? null;
}

export function getRelationLabel(value: unknown, labelKey = 'name'): string {
  if (value === null || value === undefined) return '—';
  if (typeof value === 'object') {
    const obj = value as Record<string, unknown>;
    return String(obj[labelKey] ?? obj['id'] ?? '—');
  }
  return String(value);
}

